def compute_mean_w(mapping_network: MappingNetwork, n_samples: int = 4096,
                   device = 'cuda') -> torch.Tensor:
    """Estimate the mean w by averaging many samples from the mapping network."""
    with torch.no_grad():
        z = torch.randn(n_samples, 512, device=device)
        w_samples = mapping_network(z)
    return w_samples.mean(dim=0, keepdim=True)  # (1, w_dim)


def truncated_w(mapping_network, z, mean_w, psi=0.7):
    w = mapping_network(z)
    return mean_w + psi * (w - mean_w)
